mapper.select:
SELECT *
FROM PAYMENT
WHERE PAYMENT_ID = #{paymentId}

SELECT *
FROM SETTLEMENT
WHERE SETTLEMENT_ID = #{settlementId}

SELECT NVL(SUM(REMAIN_AMOUNT), 0)
FROM ACCOUNT_RECEIVABLE
WHERE CUSTOMER_ID = #{customerId}

SELECT NVL(SUM(TOTAL_AMOUNT), 0)
FROM SALES_INVOICE
WHERE ISSUE_DATE BETWEEN #{startDate} AND #{endDate}

SELECT NVL(SUM(TOTAL_AMOUNT), 0)
FROM PURCHASE_INVOICE
WHERE ISSUE_DATE BETWEEN #{startDate} AND #{endDate}

SELECT NVL(SUM(REMAIN_AMOUNT), 0)
FROM ACCOUNT_RECEIVABLE
WHERE CREATED_AT BETWEEN #{startDate} AND #{endDate}

SELECT NVL(SUM(REMAIN_AMOUNT), 0)
FROM ACCOUNT_PAYABLE
WHERE CREATED_AT BETWEEN #{startDate} AND #{endDate}

SELECT (SELECT NVL(SUM(TOTAL_AMOUNT),0) FROM SALES_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND CUSTOMER_ID = #{customerId}
) AS TOTAL_SALES, (SELECT NVL(SUM(TOTAL_AMOUNT),0) FROM PURCHASE_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
) AS TOTAL_PURCHASE, (SELECT NVL(SUM(REMAIN_AMOUNT),0) FROM ACCOUNT_RECEIVABLE WHERE 1 = 1
AND DUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND DUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND CUSTOMER_ID = #{customerId}
) AS TOTAL_RECEIVABLE, (SELECT NVL(SUM(REMAIN_AMOUNT),0) FROM ACCOUNT_PAYABLE WHERE 1 = 1
AND DUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND DUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
) AS TOTAL_PAYABLE, ( (SELECT NVL(SUM(TOTAL_AMOUNT),0) FROM SALES_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND CUSTOMER_ID = #{customerId}
) - (SELECT NVL(SUM(TOTAL_AMOUNT),0) FROM PURCHASE_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
) ) AS GROSS_PROFIT, NVL( ROUND( ( ( (SELECT NVL(SUM(TOTAL_AMOUNT), 0) FROM SALES_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND CUSTOMER_ID = #{customerId}
) - (SELECT NVL(SUM(TOTAL_AMOUNT), 0) FROM PURCHASE_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
) ) / NULLIF( (SELECT NVL(SUM(TOTAL_AMOUNT),0) FROM SALES_INVOICE WHERE 1 = 1
AND ISSUE_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND ISSUE_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND CUSTOMER_ID = #{customerId}
), 0 ) ) * 100, 2 ), 0 ) AS PROFIT_RATE FROM DUAL

SELECT REMAIN_AMOUNT
FROM ACCOUNT_RECEIVABLE
WHERE AR_ID = #{arId}
